class ApplicantsPage(QtWidgets.QWidget):
    """
    Full Applicants page — slots into the Industrial Attachment sub-tab stack
    (or stackedWidget_2 index 0).

    Layout
    ──────
    Left scroll area
      • Page header + breadcrumb
      • 5 stat cards (Total / New / Under Review / Shortlisted / Rejected)
      • Filter row (Status / Department / Course / Date Range / Search / Actions)
      • Applicants List section: table + pagination
      • Bottom analytics row: trend line | dept bars | institution donut | status bars
    Right panel (fixed 280px)
      • Application Overview donut
      • Top Programs Applied
      • Quick Actions
    """

    def __init__(self, parent=None):
        super().__init__(parent)
        self.setObjectName("Applicants_Page")
        self.setStyleSheet(f"background:{_BG};")
        self._applicants = list(SAMPLE_APPLICANTS)
        self._build_ui()
        self._populate_table()

    # ──────────────────────────────────────────────────────────────────────────
    def _build_ui(self):
        outer = QtWidgets.QHBoxLayout(self)
        outer.setContentsMargins(0, 0, 0, 0); outer.setSpacing(0)

        # ════════════════════ LEFT SCROLL AREA ═══════════════════════════════
        scroll = QtWidgets.QScrollArea()
        scroll.setWidgetResizable(True)
        scroll.setFrameShape(QtWidgets.QFrame.Shape.NoFrame)
        scroll.setHorizontalScrollBarPolicy(Qt.ScrollBarPolicy.ScrollBarAlwaysOff)
        scroll.setStyleSheet("background:transparent;border:none;")

        lc = QtWidgets.QWidget(); lc.setStyleSheet(f"background:{_BG};")
