    # ──────────────────────────────────────────────────────────────────────────
    # TABLE POPULATION
    # ──────────────────────────────────────────────────────────────────────────
    def _populate_table(self, data: list = None):
        rows = data if data is not None else self._applicants
        self.table.setRowCount(0)
        for i, app in enumerate(rows):
            num, name, reg_no, inst, course, dept, applied_on, status = app
            self.table.insertRow(i)
            self.table.setRowHeight(i, 50)

            self._set_item(i, 0, str(i + 1))

            applicant_w = QtWidgets.QWidget()
            aw_hl = QtWidgets.QHBoxLayout(applicant_w)
            aw_hl.setContentsMargins(6, 0, 6, 0); aw_hl.setSpacing(8)
            colour = AVATAR_COLOURS[i % len(AVATAR_COLOURS)]
            aw_hl.addWidget(_AvatarCircle(name, colour))
            name_lbl = QtWidgets.QLabel(name)
            name_lbl.setStyleSheet(f"color:{_TEXT_DARK};font-size:12px;font-weight:600;")
            aw_hl.addWidget(name_lbl)
            aw_hl.addStretch()
            self.table.setCellWidget(i, 1, applicant_w)

            self._set_item(i, 2, reg_no)
            self._set_item(i, 3, inst)
            self._set_item(i, 4, course)
            self._set_item(i, 5, dept)
            self._set_item(i, 6, applied_on)

            fg, bg = STATUS_COLOURS.get(status, (_TEXT_MID, "#f3f4f6"))
            self.table.setCellWidget(i, 7, self._centre(_Badge(status, fg, bg)))
            self.table.setCellWidget(i, 8, self._action_widget(i))

        count = len(rows)
        self.showing_lbl.setText(
            f"Showing 1 to {min(10, count)} of {count} applicants")

    def _set_item(self, row, col, text):
        it = QtWidgets.QTableWidgetItem(text)
        it.setFlags(it.flags() & ~Qt.ItemFlag.ItemIsEditable)
        self.table.setItem(row, col, it)

    @staticmethod
    def _centre(widget) -> QtWidgets.QWidget:
        w = QtWidgets.QWidget()
        hl = QtWidgets.QHBoxLayout(w)
        hl.addWidget(widget)
        hl.setAlignment(Qt.AlignmentFlag.AlignLeft | Qt.AlignmentFlag.AlignVCenter)
        hl.setContentsMargins(6, 0, 0, 0)
        return w

    def _action_widget(self, row: int) -> QtWidgets.QWidget:
        w = QtWidgets.QWidget()
        hl = QtWidgets.QHBoxLayout(w)
        hl.setContentsMargins(4, 0, 4, 0); hl.setSpacing(4)
        for ico, tip, col, slot in [
            ("👁", "View",   "#64748b", lambda _, r=row: self._on_view(r)),
            ("✏",  "Edit",   "#2563eb", lambda _, r=row: self._on_edit(r)),
            ("🗑",  "Delete", "#dc2626", lambda _, r=row: self._on_delete(r)),
        ]:
            b = QtWidgets.QPushButton(ico)
            b.setFixedSize(24, 24)
            b.setToolTip(tip)
            b.setCursor(QtGui.QCursor(Qt.CursorShape.PointingHandCursor))
            b.setStyleSheet(f"""
                QPushButton {{
                    background:{col}22; color:{col};
                    border:1px solid {col}44;
                    border-radius:5px; font-size:11px;
                }}
                QPushButton:hover {{ background:{col}44; }}
            """)
            b.clicked.connect(slot)
            hl.addWidget(b)
        hl.addStretch()
        return w

    # ──────────────────────────────────────────────────────────────────────────
    # SLOTS
    # ──────────────────────────────────────────────────────────────────────────
    def _apply_filters(self):
        text = self.search_edit.text().lower()
        status_f = self._status_combo.currentText()
        dept_f = self._dept_combo.currentText()
        course_f = self._course_combo.currentText()
        results = []
        for app in self._applicants:
            num, name, reg_no, inst, course, dept, applied_on, status = app
            if status_f != "All Statuses" and status != status_f: continue
            if dept_f != "All Departments" and dept != dept_f: continue
            if course_f != "All Programs" and course != course_f: continue
            if text and not any(text in v.lower() for v in
                                (name, reg_no, inst, course, dept)):
                continue
            results.append(app)
        self._populate_table(results)

    def _on_add(self):
        dlg = NewApplicationDialog(self)
        dlg.application_saved.connect(self._append_application)
        dlg.exec()

    def _append_application(self, data: dict):
        from datetime import date
        new_num = len(self._applicants) + 1
        reg_no = f"REG/2025/{new_num:03d}"
        self._applicants.insert(0, (
            new_num, data["name"], reg_no, data["institution"], data["course"],
            data["department"], date.today().strftime("%d %b %Y"), data["status"]
        ))
        self._apply_filters()
        QtWidgets.QMessageBox.information(
            self, "Application Registered",
            f"✅  '{data['name']}' has been registered successfully."
        )

    def _on_view(self, row: int):
        if row >= len(self._applicants): return
        a = self._applicants[row]
        QtWidgets.QMessageBox.information(
            self, "Applicant Details",
            f"<b>{a[1]}</b><br>Reg. No: {a[2]}<br>Institution: {a[3]}<br>"
            f"Course: {a[4]}<br>Department: {a[5]}<br>Applied On: {a[6]}<br>"
            f"Status: {a[7]}"
        )

    def _on_edit(self, row: int):
        if row >= len(self._applicants): return
        a = self._applicants[row]
        dlg = NewApplicationDialog(self, data={
            "name": a[1], "institution": a[3], "course": a[4],
            "department": a[5], "status": a[7],
        })
        dlg.application_saved.connect(lambda d, r=row: self._save_edit(r, d))
        dlg.exec()

    def _save_edit(self, row: int, data: dict):
        old = self._applicants[row]
        self._applicants[row] = (
            old[0], data["name"], old[2], data["institution"], data["course"],
            data["department"], old[6], data["status"]
        )
        self._apply_filters()

    def _on_delete(self, row: int):
        if row >= len(self._applicants): return
        name = self._applicants[row][1]
        reply = QtWidgets.QMessageBox.question(
            self, "Delete Applicant",
            f"Delete <b>{name}</b>? This cannot be undone.",
            QtWidgets.QMessageBox.StandardButton.Yes |
            QtWidgets.QMessageBox.StandardButton.No,
            QtWidgets.QMessageBox.StandardButton.No,
        )
        if reply == QtWidgets.QMessageBox.StandardButton.Yes:
            self._applicants.pop(row)
            self._apply_filters()

    def _on_filter_menu(self):
        QtWidgets.QMessageBox.information(
            self, "Advanced Filters",
            "Advanced filter panel will be available in the next sprint."
        )

    def _on_export(self):
        QtWidgets.QMessageBox.information(
            self, "Export",
            "Export functionality will be connected in the next sprint."
        )

    def _on_placeholder(self):
        QtWidgets.QMessageBox.information(
            self, "Coming Soon",
            "This feature will be available in the next sprint."
        )